const webhookData = $('Webhook Trigger').first().json;
const b = webhookData.body ?? webhookData;
const run_id = b.run_id || b.runId || b.runID;
const query = b.enforced_query || b.query || b.enforcedQuery;
const max_results = Number(b.max_results ?? b.maxResults ?? 20);
if (!run_id || !query) {
  return [{ json: { ok:false, error:{code:'MISSING_FIELDS', message:'run_id and enforced_query are required'}, run_id: run_id ?? null, query: query ?? null, max_results } }];
}
return [{ json: { ok:true, run_id, query, max_results: Math.max(1, Math.min(30, max_results)), scope: b.scope ?? null, metro: b.metro ?? null } }];

const run_id = $('Normalize Input').first().json.run_id;
const query = $('Normalize Input').first().json.query;
const max_results = $('Normalize Input').first().json.max_results || 20;
const r = $json;
const items = (r && (r.data || r.results || r.items)) || [];
const arr = Array.isArray(items) ? items : [];

const top = arr.slice(0, max_results).map((it, i) => {
  const title = it.title || it.name || null;
  const url = it.url || it.link || null;
  const snippet = it.description || it.snippet || null;
  return `${i+1}. ${title ?? ''}\nURL: ${url ?? ''}\nSnippet: ${snippet ?? ''}`.trim();
});

const search_context = `Query: ${query}\n\nResults:\n${top.join('\n\n')}`;
return [{ json: { run_id, query, search_context, result_count: arr.length } }];

