let txt = $json?.choices?.[0]?.message?.content ?? '';
txt = String(txt).trim();
let parsed;
try { parsed = JSON.parse(txt); } catch(e) {
  const m = txt.match(/\[[\s\S]*\]/);
  if (m) parsed = JSON.parse(m[0]); else parsed = [];
}
const opportunities = Array.isArray(parsed) ? parsed : (parsed.opportunities || []);
const run_id = $('Normalize Input').first().json.run_id;
const cleaned = opportunities.slice(0, $('Normalize Input').first().json.max_results).map(o => ({
  name: o.name ?? null,
  organization_type: o.organization_type ?? null,
  website: o.website ?? null,
  location: o.location ?? null,
  mission: o.mission ?? null,
  source_url: o.source_url ?? o.url ?? null,
  confidence: (typeof o.confidence === 'number') ? o.confidence : null,
  evidence: o.evidence ?? null
}));
return [{ json: { run_id, status:'completed', results: cleaned } }];

